20	#define EPSILON (1e-20)
21	
22	bool almostEqual(float a, float b, float atol = 1e-5, float rtol = 1e-8)
23	{
24	    // Params: a = value to compare and b = reference
25	    // This function follows implementation of numpy.isclose(), which checks
26	    //   abs(a - b) <= (atol + rtol * abs(b)).
27	    // Note that the inequality above is asymmetric where b is considered as
28	    // a reference value. To account into both absolute/relative errors, it
29	    // uses absolute tolerance and relative tolerance at the same time. The
30	    // default values of atol and rtol borrowed from numpy.isclose(). For the
31	    // case of nan value, the result will be true.
32	    if (isnan(a) && isnan(b)) {
33	        return true;
34	    }
35	    return fabs(a - b) <= (atol + rtol * fabs(b));
36	}
37	
38	template<typename T>
39	bool checkResult(std::string name, T* out, T*ref, size_t size, float atol, float rtol) {
40	    size_t failures = 0;
41	    float relative_gap = 0.0f;;
42	
43	    for (size_t i = 0; i < size; ++i) {
44	        // The values for the output and the reference.
45	        float a = (float)out[i];
46	        float b = (float)ref[i];
47	
48	        bool ok = almostEqual(a, b, atol, rtol);
49	        // Print the error.
50	        if (!ok && failures < 4) {
51	            FT_LOG_ERROR(">> invalid result for i=%lu:", i);
52	            FT_LOG_ERROR(">>    found......: %10.6f", a);
53	            FT_LOG_ERROR(">>    expected...: %10.6f", b);
54	            FT_LOG_ERROR(">>    error......: %.6f", fabsf(a - b));
55	            FT_LOG_ERROR(">>    tol........: %.6f", atol + rtol * fabs(b));
56	        }
57	        // Update the number of failures.
58	        failures += ok ? 0 : 1;
59	        // Update the relative gap.
