133	template<typename T>
134	void computeQkSoftmax(T*           attn_score,
135	                      const T*     qk,
136	                      const T*     attn_mask,
137	                      const T*     pos_bias,
138	                      const size_t batch_size,
139	                      const size_t num_heads,
140	                      const size_t q_length,
141	                      const size_t k_length,
142	                      const T      qk_scale)
143	{
144	    // attn_score [batch_size, num_heads, q_length, k_length]
145	    // qk         [batch_size, num_heads, q_length, k_length]
146	    // attn_mask  [batch_size, 1, q_length, k_length]
147	    // pos_bias   [1, num_heads, q_length, k_length]
148	
149	    // batch, head index.
150	    for (size_t bhi = 0; bhi < batch_size * num_heads; ++bhi) {
151	        size_t bi = bhi / num_heads;  // batch index.
152	        size_t hi = bhi % num_heads;  // head index.
153	        // The attention mask of the current batch.
154	        const T* mask = &attn_mask[bi * q_length * k_length];
155	        // The position bias of the current head.
156	        const T* head_pos_bias = pos_bias != nullptr ? &pos_bias[hi * q_length * k_length] : nullptr;
157	
158	        for (size_t qi = 0; qi < q_length; ++qi) {
159	            float maxval = -FLT_MAX;
160	            for (size_t ki = 0; ki < k_length; ++ki) {
161	                size_t qk_idx = qi * k_length + ki;
162	                if (int(mask[qk_idx]) > 0) {  // mask = 0 or 1.
163	                    float val = (float)safe_add_bias(::math::mul(qk_scale, qk[qk_idx]), head_pos_bias, qk_idx);
164	                    if (val > maxval) {
165	                        maxval = val;
166	                    }
167	                }
168	            }
169	            float sum = 0.0f;
170	            for (size_t ki = 0; ki < k_length; ++ki) {
171	                size_t qk_idx = qi * k_length + ki;
172	                if (int(mask[qk_idx]) > 0) {  // mask = 0 or 1.
173	                    float val = (float)safe_add_bias(::math::mul(qk_scale, qk[qk_idx]), head_pos_bias, qk_idx);
174	                    sum += expf(val - maxval);
175	                }
176	            }
177	            for (size_t ki = 0; ki < k_length; ++ki) {
178	                size_t qk_idx = qi * k_length + ki;
179	                if (int(mask[qk_idx]) > 0) {  // mask = 0 or 1.
180	                    float val = (float)safe_add_bias(::math::mul(qk_scale, qk[qk_idx]), head_pos_bias, qk_idx);
181	                    attn_score[qk_idx] = static_cast<T>(expf(val - maxval) / (sum + EPSILON));
182	                }
183	                else {
184	                    attn_score[qk_idx] = T(0.0f);
185	                }
186	            }
187	        }
188	
189	        // Move the data pointers to the next.
190	        attn_score += q_length * k_length;
191	        qk         += q_length * k_length;
192	    }
193	}
