56	void computeProb(T* probs, T* logits, int batch_size, int vocab_size)
57	{
58	    // Compute the log probability from logits.
59	    //   logits = batch_size x vocab_size vector.
60	    //   logprobs = log(softmax(logits)) (softmax along with vocab dimension)
61	    for (int bidx = 0; bidx < batch_size; ++bidx) {
62	        float sum = 0.0f;
63	        for (int i = 0; i < vocab_size; ++i) {
64	            sum += expf((float)logits[bidx * vocab_size + i]);
65	        }
66	        for (int i = 0; i < vocab_size; ++i) {
67	            int idx    = bidx * vocab_size + i;
68	            probs[idx] = static_cast<T>(expf((float)logits[idx]) / (sum + EPSILON));
69	        }
70	    }
